<?phpclass Agama_records_model extends CI_Model {	    public function add($data) {        $this->db->insert('agama_records',$data);    }		public function record_count() {        return $this->db->count_all('agama_records');    }	public function getall() {		$query = $this->db->order_by('date_created', 'desc')->get('agama_records');				if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}	public function get($id) {		$query = $this->db->where('id', $id)->get('agama_records', 1, 0);		if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}}